window.sortingListManager=function(){let e=(e,t,n)=>{fetch(t,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({oldIndex:e.oldIndex,newIndex:e.newIndex})}).catch(e=>{console.log(e),alert(n||"Unable to sort the list")})};return{create:(t,n,o)=>{var r,a=document.querySelector(t);if(!a){console.log("Unable to find the sortable element. The given selector is: "+t);return}if(!(r=n||a.getAttribute("data-sort-uri"))){console.log("Unable to determine the sort post URI. Either pass it to the create function or set it as data-sort-uri to the sorting element.");return}Sortable.create(a,{handle:".ui-sortable-handle",animation:150,filter:".ignore-elements",draggable:".item",onUpdate:function(t){e(t,r,o)}})}}}();
